-- Atualiza o conteúdo do template reuniao_lembrete com HTML completo
update public.email_templates
set
  body_html = '<p>Olá <strong>{{nome_participante}}</strong>,</p><p>Este é um lembrete de que você tem uma reunião agendada para <strong>amanhã</strong>.</p><table width="100%" cellpadding="0" cellspacing="0" style="margin:24px 0;"><tr><td style="background:#eff6ff;border-left:4px solid #1e40af;border-radius:4px;padding:20px 24px;"><p style="margin:0 0 10px 0;font-size:16px;font-weight:bold;color:#1e3a8a;">{{titulo_reuniao}}</p><p style="margin:0;font-size:14px;color:#374151;">📅 &nbsp;{{data_reuniao}}</p></td></tr></table><p><a href="{{link_reuniao}}" style="display:inline-block;background:#1e40af;color:#ffffff;padding:12px 24px;border-radius:6px;text-decoration:none;font-size:14px;font-weight:bold;">Ver detalhes da reunião</a></p><p style="margin-top:32px;color:#6b7280;font-size:13px;">Se você não for participar desta reunião, entre em contato com o responsável para atualizar a lista de participantes.</p>',
  body_rich_text = public.text_to_tiptap(E'Olá {{nome_participante}},\n\nEste é um lembrete de que você tem uma reunião agendada para amanhã.\n\nReunião: {{titulo_reuniao}}\nData e horário: {{data_reuniao}}\n\nAcesse o sistema para ver todos os detalhes:\n{{link_reuniao}}\n\nSe você não for participar desta reunião, entre em contato com o responsável para atualizar a lista de participantes.'),
  default_body_html = '<p>Olá <strong>{{nome_participante}}</strong>,</p><p>Este é um lembrete de que você tem uma reunião agendada para <strong>amanhã</strong>.</p><table width="100%" cellpadding="0" cellspacing="0" style="margin:24px 0;"><tr><td style="background:#eff6ff;border-left:4px solid #1e40af;border-radius:4px;padding:20px 24px;"><p style="margin:0 0 10px 0;font-size:16px;font-weight:bold;color:#1e3a8a;">{{titulo_reuniao}}</p><p style="margin:0;font-size:14px;color:#374151;">📅 &nbsp;{{data_reuniao}}</p></td></tr></table><p><a href="{{link_reuniao}}" style="display:inline-block;background:#1e40af;color:#ffffff;padding:12px 24px;border-radius:6px;text-decoration:none;font-size:14px;font-weight:bold;">Ver detalhes da reunião</a></p><p style="margin-top:32px;color:#6b7280;font-size:13px;">Se você não for participar desta reunião, entre em contato com o responsável para atualizar a lista de participantes.</p>',
  default_body_rich_text = public.text_to_tiptap(E'Olá {{nome_participante}},\n\nEste é um lembrete de que você tem uma reunião agendada para amanhã.\n\nReunião: {{titulo_reuniao}}\nData e horário: {{data_reuniao}}\n\nAcesse o sistema para ver todos os detalhes:\n{{link_reuniao}}\n\nSe você não for participar desta reunião, entre em contato com o responsável para atualizar a lista de participantes.')
where slug = 'reuniao_lembrete';
